private fun String?.safeUser(): String {
    if (this.isNullOrBlank()) return "<unknown>"
    val trimmed = trim()
    return if (trimmed.length <= 3) "***" else "${trimmed.take(1)}***${trimmed.takeLast(1)}"
}

private fun Map<String, Any?>.redactedString(): String {
    if (isEmpty()) return "{}"
    return entries.joinToString(prefix = "{", postfix = "}") { (key, value) ->
        "$key=${value.redactValue(key)}"
    }
}

private fun Map<String, String>.redactedHeadersString(): String {
    if (isEmpty()) return "{}"
    return entries.joinToString(prefix = "{", postfix = "}") { (key, value) ->
        "$key=${value.redactHeaderValue(key)}"
    }
}

private fun Any?.redactValue(key: String): String {
    val sensitiveKeys = setOf("password", "pass", "token", "access_token", "refresh_token", "secret", "authorization", "auth")
    return if (sensitiveKeys.any { key.contains(it, ignoreCase = true) }) "***REDACTED***" else this.toString()
}

private fun String.redactHeaderValue(key: String): String {
    val sensitiveKeys = setOf("authorization", "cookie", "set-cookie", "x-api-key", "api-key")
    return if (sensitiveKeys.any { key.contains(it, ignoreCase = true) }) "***REDACTED***" else this
}

class AuthLogger {
    fun onLoginAttempt(username: String?, password: String?) {
        AppLogger.d(
            "AUTH_ATTEMPT user=%s password_present=%s",
            username.safeUser(),
            !password.isNullOrEmpty()
        )
    }

    fun onLoginResult(username: String?, success: Boolean, error: Throwable? = null) {
        if (success) {
            AppLogger.logAuthAttempt(username, true)
        } else {
            AppLogger.logAuthAttempt(username, false, error?.message ?: "unknown")
            error?.let { AppLogger.logException(it, "Authentication failed") }
        }
    }
}

