class GlobalExceptionLogger : Thread.UncaughtExceptionHandler {
    private val defaultHandler = Thread.getDefaultUncaughtExceptionHandler()

    override fun uncaughtException(thread: Thread, throwable: Throwable) {
        AppLogger.logException(throwable, "Uncaught exception on thread=${thread.name}")
        defaultHandler?.uncaughtException(thread, throwable)
    }
}

fun installGlobalExceptionLogging() {
    Thread.setDefaultUncaughtExceptionHandler(GlobalExceptionLogger())
}

